35	const PROCESSING_FEE = 5;
36	const FIRST_INSURANCE_SURCHARGE = 0.1;
37	const LOYALTY_DISCOUNT = 0.2;
38	const LOYALTY_THRESHOLD_YEARS = 2;
39	const FOLLOWUP_CONTRACT_DISCOUNT = 0.15;
40	const CURSED_SURCHARGE = 0.5;
41	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
42	const HIGH_ENCHANTMENT_THRESHOLD = 5;
43	const DEDUCTIBLE_PER_DAMAGE = 100;
44	const CAP_MULTIPLIER = 2;
45	
46	const ITEM_BASE_PREMIUM: Record<string, number> = {
47	  sword: 100,
48	  rune: 25,
49	  moonstone: 25,
50	};
51	
52	const ITEM_INSURANCE_VALUE: Record<string, number> = {
53	  sword: 1000,
54	  rune: 250,
55	};
56	
57	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
58	const COMPONENT_BLOCK_SIZE = 3;
59	const COMPONENT_BLOCK_PREMIUM = 60;
60	
61	const groupCountsByType = (items: Item[]): Map<string, number> => {
62	  const counts = new Map<string, number>();
63	  for (const item of items) counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
64	  return counts;
65	};
66	
67	const basePremiumForGroup = (type: string, count: number): number => {
68	  if (COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE) return COMPONENT_BLOCK_PREMIUM;
69	  return count * ITEM_BASE_PREMIUM[type];
70	};
71	
72	const sumBasePremium = (counts: Map<string, number>): number => {
73	  let total = 0;
74	  for (const [type, count] of counts) total += basePremiumForGroup(type, count);
75	  return total;
76	};
77	
78	const isHighlyEnchanted = (item: Item): boolean =>
79	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
80	
81	const surchargeRateForItem = (item: Item): number =>
82	  (item.cursed ? CURSED_SURCHARGE : 0) +
83	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE : 0);
84	
85	const surchargeForItem = (item: Item): number =>
86	  ITEM_BASE_PREMIUM[item.type] * surchargeRateForItem(item);
87	
88	const itemSurcharges = (items: Item[]): number =>
89	  items.reduce((total, item) => total + surchargeForItem(item), 0);
90	
91	const calculatePremium = (
92	  items: Item[],
93	  yearsWithMHPCO: number,
94	  isFollowUpContract: boolean,
95	): number => {
96	  const base = sumBasePremium(groupCountsByType(items));
97	  const surcharges = itemSurcharges(items);
98	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_SURCHARGE;
99	  const loyaltyDiscount =
100	    yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? base * LOYALTY_DISCOUNT : 0;
101	  const followUpDiscount = isFollowUpContract ? base * FOLLOWUP_CONTRACT_DISCOUNT : 0;
102	  return Math.ceil(
103	    base + surcharges + firstInsuranceSurcharge - loyaltyDiscount - followUpDiscount + PROCESSING_FEE,
104	  );
105	};
106	
107	type Policy = {
108	  items: Item[];
109	  remainingCap: number;
110	};
111	
112	const insuranceSum = (items: Item[]): number =>
113	  items.reduce((sum, item) => sum + ITEM_INSURANCE_VALUE[item.type], 0);
114	
115	const payoutForDamage = (damage: Damage): number =>
116	  Math.max(0, damage.amount - DEDUCTIBLE_PER_DAMAGE);
117	
118	const claimPayout = (policy: Policy, incident: Incident): number => {
119	  const grossPayout = incident.damages.reduce((sum, d) => sum + payoutForDamage(d), 0);
120	  return Math.floor(Math.min(grossPayout, policy.remainingCap));
121	};
122	
123	export const runScenario = (scenario: Scenario): ScenarioResult => {
124	  const policies: Policy[] = [];
125	  let quoteCount = 0;
126	  const results: StepResult[] = scenario.steps.map((step) => {
127	    if (step.op === "quote") {
128	      const isFollowUpContract = quoteCount >= 1;
129	      quoteCount += 1;
130	      policies.push({ items: step.items, remainingCap: insuranceSum(step.items) * CAP_MULTIPLIER });
131	      return {
132	        premium: calculatePremium(step.items, scenario.customer.yearsWithMHPCO, isFollowUpContract),
133	      };
134	    }
135	    const policy = policies[step.policy];
136	    const payout = claimPayout(policy, step.incident);
137	    policy.remainingCap -= payout;
138	    return { payout, remainingCap: policy.remainingCap };
139	  });
140	  return { results };
141	};
